'use strict';

/**
 * createRateLimiter — TRUE sliding window rate limiting middleware for Express.
 *
 * Unlike a fixed-window limiter (which resets a counter at fixed intervals and
 * can allow bursts of up to 2x the limit around the boundary), this stores the
 * timestamp of every request per client and, on each new request, evicts
 * timestamps older than `windowMs` before counting. The window therefore slides
 * continuously with "now" rather than snapping to fixed buckets.
 *
 * @param {Object}   [options]
 * @param {number}   [options.windowMs=60000]   Window size in milliseconds.
 * @param {number}   [options.maxRequests=100]  Max requests allowed per window.
 * @param {Function} [options.keyGenerator]     (req) => string. Defaults to req.ip.
 * @returns {Function} Express middleware, augmented with a `close()` method.
 */
function createRateLimiter(options = {}) {
  const {
    windowMs = 60000,
    maxRequests = 100,
    keyGenerator = (req) => req.ip,
  } = options;

  if (!Number.isFinite(windowMs) || windowMs <= 0) {
    throw new TypeError('windowMs must be a positive number');
  }
  if (!Number.isFinite(maxRequests) || maxRequests <= 0) {
    throw new TypeError('maxRequests must be a positive number');
  }

  // Map<clientKey, number[]> — each value is an array of request timestamps (ms),
  // stored oldest-first.
  const hits = new Map();

  /**
   * Periodic cleanup: drop entries whose newest timestamp is already stale.
   * Bounds memory for clients that stop sending requests. This is purely a
   * memory optimization — per-request eviction already guarantees correctness.
   */
  const cleanupTimer = setInterval(() => {
    const cutoff = Date.now() - windowMs;
    for (const [key, timestamps] of hits) {
      // Newest timestamp is the last element; if even it is stale, drop the entry.
      if (timestamps.length === 0 || timestamps[timestamps.length - 1] <= cutoff) {
        hits.delete(key);
      }
    }
  }, 60000);

  // Don't let the cleanup timer keep the Node.js process alive on its own.
  if (typeof cleanupTimer.unref === 'function') {
    cleanupTimer.unref();
  }

  const middleware = function rateLimiter(req, res, next) {
    const now = Date.now();
    const cutoff = now - windowMs;
    const key = keyGenerator(req);

    let timestamps = hits.get(key);
    if (timestamps === undefined) {
      timestamps = [];
      hits.set(key, timestamps);
    }

    // Sliding window eviction: remove every timestamp older than the window.
    // Stored oldest-first, so splice off the stale prefix.
    let firstFresh = 0;
    while (firstFresh < timestamps.length && timestamps[firstFresh] <= cutoff) {
      firstFresh++;
    }
    if (firstFresh > 0) {
      timestamps.splice(0, firstFresh);
    }

    const limitHeaderValue = String(maxRequests);

    if (timestamps.length >= maxRequests) {
      // Over the limit — reject. A slot frees when the OLDEST in-window request
      // ages out, so Retry-After / Reset derive from that timestamp.
      const oldest = timestamps[0];
      const retryAfterMs = oldest + windowMs - now;
      const retryAfterSec = Math.max(1, Math.ceil(retryAfterMs / 1000));

      res.setHeader('X-RateLimit-Limit', limitHeaderValue);
      res.setHeader('X-RateLimit-Remaining', '0');
      res.setHeader('X-RateLimit-Reset', String(Math.ceil((oldest + windowMs) / 1000)));
      res.setHeader('Retry-After', String(retryAfterSec));

      res.status(429).json({
        error: 'Rate limit exceeded',
        retryAfter: retryAfterSec,
      });
      return; // Do NOT call next().
    }

    // Under the limit — record this request and allow it.
    timestamps.push(now);

    const remaining = maxRequests - timestamps.length;
    // A slot frees when the oldest in-window request ages out.
    const resetEpochSec = Math.ceil((timestamps[0] + windowMs) / 1000);

    res.setHeader('X-RateLimit-Limit', limitHeaderValue);
    res.setHeader('X-RateLimit-Remaining', String(Math.max(0, remaining)));
    res.setHeader('X-RateLimit-Reset', String(resetEpochSec));

    next();
  };

  /**
   * Stop the cleanup interval and free state so the limiter can be GC'd and the
   * timer never keeps the event loop alive. Call on shutdown / in tests.
   */
  middleware.close = function close() {
    clearInterval(cleanupTimer);
    hits.clear();
  };

  return middleware;
}

module.exports = createRateLimiter;
module.exports.createRateLimiter = createRateLimiter;
