// (Nginx reverse proxy on Linode), `app.set('trust proxy', 1)` is the right call.
app.set('trust proxy', 1);

const limiter = createRateLimiter({
  windowMs: 60000,   // 1 minute
  maxRequests: 100,  // 100 requests per sliding minute per IP
});

app.use(limiter);

app.get('/', (req, res) => res.json({ ok: true }));

const server = app.listen(3000, () => console.log('listening on :3000'));

// Graceful shutdown — clear the cleanup interval so the process can exit.
process.on('SIGTERM', () => {
  limiter.close();
  server.close();
});
