/**
 * sliding-window-rate-limiter.js
 *
 * True sliding-window rate limiting middleware for Express.js.
 *
 * Why "true" sliding window?
 *   Fixed-window limiters reset a counter every N seconds. A client can burst
 *   2× maxRequests by hitting the tail of one window and the head of the next.
 *   This implementation stores individual request timestamps per IP and always
 *   measures against a window that ends at *right now*, so no burst is possible
 *   across a boundary.
 *
 * ┌─────────────────────────────────────────────────────────────┐
 * │  NOTE — req.ip behind a reverse proxy                       │
 * │                                                             │
 * │  Express sets req.ip from X-Forwarded-For ONLY when         │
 * │  app.set('trust proxy', true) (or a hop count / CIDR range) │
 * │  is configured. Without it, req.ip is always the socket     │
 * │  address of the last network hop — usually your load        │
 * │  balancer — so every client shares one rate-limit bucket.   │
 * │                                                             │
 * │  Enable trust proxy when running behind Nginx, Cloudflare,  │
 * │  AWS ALB, etc.:                                             │
 * │    app.set('trust proxy', 1)   // trust exactly one hop     │
 * └─────────────────────────────────────────────────────────────┘
 */

'use strict';

/**
 * Creates a sliding-window rate limiter middleware.
 *
 * @param {object} [options]
 * @param {number} [options.windowMs=60000]   Rolling window size in milliseconds.
 * @param {number} [options.maxRequests=100]  Max requests allowed inside that window.
 *
 * @returns {Function} Express middleware with an attached `.close()` method that
 *                     stops the internal cleanup interval.
 */
function createRateLimiter(options = {}) {
  const windowMs    = options.windowMs    ?? 60_000; // default: 1 minute
  const maxRequests = options.maxRequests ?? 100;    // default: 100 req/window

  if (typeof windowMs !== 'number' || windowMs <= 0) {
    throw new RangeError(`windowMs must be a positive number (got ${windowMs})`);
  }
  if (typeof maxRequests !== 'number' || maxRequests < 1) {
    throw new RangeError(`maxRequests must be >= 1 (got ${maxRequests})`);
  }

  /**
   * Per-IP request log.
   *   Map<ip: string, timestamps: number[]>
   *
   * Timestamps are stored in insertion (ascending chronological) order.
   * Because requests naturally arrive in time order, a push() keeps the
   * array sorted — no explicit sort() is ever needed.
   */
  const store = new Map();

  // ── Periodic memory management ──────────────────────────────────────────
  //
  // Without cleanup, the store accumulates stale entries for IPs that have
  // gone quiet. Every 60 s we walk the map and:
  //   • Trim any leading timestamps that have fallen outside the window.
  //   • Evict the entry entirely when no active timestamps remain.
  const cleanupInterval = setInterval(() => {
    const cutoff = Date.now() - windowMs;

    for (const [ip, timestamps] of store) {
      // Binary-search-equivalent: find the first index still inside the window.
      // Linear scan is fine here because entries accumulate at the front and
      // the array is always short (≤ maxRequests elements by invariant).
      let i = 0;
      while (i < timestamps.length && timestamps[i] <= cutoff) i++;

      if (i === timestamps.length) {
        store.delete(ip);                        // all stale — evict entirely
      } else if (i > 0) {
        store.set(ip, timestamps.slice(i));      // trim leading stale entries
      }
      // i === 0 → everything is fresh, nothing to do
    }
  }, 60_000);

  // Prevent the interval from keeping the Node.js event loop alive once the
  // server is closed. Critical for test suites and graceful-shutdown scripts.
  if (typeof cleanupInterval.unref === 'function') {
    cleanupInterval.unref();
  }

  // ── Middleware ───────────────────────────────────────────────────────────
  /**
   * Sliding-window check — runs on every request.
   *
   * Algorithm:
   *   1. Compute windowStart = now − windowMs.
   *   2. Drop all timestamps ≤ windowStart from this IP's log.
   *   3. If remaining count ≥ maxRequests → reject (429).
   *   4. Otherwise, append `now`, set informational headers, call next().
   */
  function middleware(req, res, next) {
    const now         = Date.now();
    const windowStart = now - windowMs;

    // Identify the client. See the proxy note at the top of the file.
    const ip = req.ip ?? req.socket?.remoteAddress ?? 'unknown';

    // ── Steps 1 & 2: Retrieve log, evict stale timestamps ───────────────
    const raw = store.get(ip) ?? [];

    // Scan from the front (stale entries accumulate there).
    let firstValid = 0;
    while (firstValid < raw.length && raw[firstValid] <= windowStart) {
      firstValid++;
    }
    // Avoid allocating a new array when nothing was evicted.
    const timestamps   = firstValid > 0 ? raw.slice(firstValid) : raw;
    const currentCount = timestamps.length;

    // ── Step 3: Reject if at or over the limit ───────────────────────────
    if (currentCount >= maxRequests) {
      //
      // The client must wait until the oldest timestamp in the window ages
      // out. At that moment the count drops to maxRequests − 1 and the next
      // request will succeed.
      //
      //   retryAfterMs = (timestamps[0] + windowMs) − now
      //                = timestamps[0] − (now − windowMs)
      //                = timestamps[0] − windowStart        ← same value
      //
      const retryAfterMs  = (timestamps[0] + windowMs) - now;
      const retryAfterSec = Math.ceil(retryAfterMs / 1000);

      store.set(ip, timestamps);   // persist the pruned (but full) window

      res.setHeader('Retry-After', retryAfterSec);

      // Do NOT call next().
      return res
        .status(429)
        .json({ error: 'Rate limit exceeded', retryAfter: retryAfterSec });
    }

    // ── Step 4: Allow — record this request ─────────────────────────────
    // push() keeps the array sorted (requests arrive in chronological order).
    timestamps.push(now);
    store.set(ip, timestamps);

    // X-RateLimit-Reset: the epoch second when the *oldest* slot in the
    // window expires — the earliest moment the remaining count ticks upward.
    const resetEpochSec = Math.ceil((timestamps[0] + windowMs) / 1000);

    res.setHeader('X-RateLimit-Limit',     maxRequests);
    res.setHeader('X-RateLimit-Remaining', maxRequests - timestamps.length);
    res.setHeader('X-RateLimit-Reset',     resetEpochSec);

    next();
  }

  // ── Lifecycle helper ─────────────────────────────────────────────────────
  /**
   * Stop the internal cleanup interval.
   * Call this when your server shuts down so the process can exit cleanly.
   *
   *   process.on('SIGTERM', () => { limiter.close(); server.close(); });
   */
  middleware.close = function close() {
    clearInterval(cleanupInterval);
  };

  return middleware;
}

module.exports = { createRateLimiter };
